    {
      "keystrokes": "TOPDIR=$(tar -tzf /app/vendor/sqlite-fossil-release.tar.gz | head -1 | cut -d/ -f1)\n",
      "duration": 0.1
    },
    {
      "keystrokes": "cd /app/sqlite/src/$TOPDIR\n",
      "duration": 0.1
    },
    {
      "keystrokes": "gcc --version\n",
      "duration": 0.5
    },
    {
      "keystrokes": "SQLITE3_C=$(find . -name 'sqlite3.c' | head -1); SHELL_C=$(find . -name 'shell.c' | head -1); echo \"SQLITE3_C=$SQLITE3_C\"; echo \"SHELL_C=$SHELL_C\"\n",
      "duration": 0.5
    },
    {
      "keystrokes": "gcc --coverage -O0 -g \"$SQLITE3_C\" \"$SHELL_C\" -o /app/sqlite/bin/sqlite3 -ldl -lpthread -lm\n",
      "duration": 15.0
    },
    {
      "keystrokes": "ls -la /app/sqlite/bin\n",
      "duration": 0.1
    },
    {
      "keystrokes": "export PATH=\"/app/sqlite/bin:$PATH\"\n",
      "duration": 0.1
