    {
      "keystrokes": "sqlite3 --version\n",
      "duration": 0.5
    },
    {
      "keystrokes": "find . -maxdepth 2 -name '*.gcno' -or -name '*.gcda' | head -n 20\n",
      "duration": 0.5
    }
  ],
  "task_complete": false
}

